CREATE TABLE `battles` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `player1_id` bigint unsigned NOT NULL,
  `player2_id` bigint unsigned DEFAULT NULL,
  `player1_deck_id` bigint unsigned NOT NULL,
  `player2_deck_id` bigint unsigned DEFAULT NULL,
  `battle_state` json DEFAULT NULL,
  `status` enum('waiting','in_progress','finished','cancelled') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'waiting',
  `winner_id` bigint unsigned DEFAULT NULL,
  `current_turn_user_id` bigint unsigned DEFAULT NULL,
  `turn_number` int NOT NULL DEFAULT '1',
  `last_action_at` timestamp NULL DEFAULT NULL,
  `started_at` timestamp NULL DEFAULT NULL,
  `finished_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `battles_player1_deck_id_foreign` (`player1_deck_id`),
  KEY `battles_player2_deck_id_foreign` (`player2_deck_id`),
  KEY `battles_winner_id_foreign` (`winner_id`),
  KEY `battles_current_turn_user_id_foreign` (`current_turn_user_id`),
  KEY `battles_status_index` (`status`),
  KEY `battles_player1_id_status_index` (`player1_id`,`status`),
  KEY `battles_player2_id_status_index` (`player2_id`,`status`),
  CONSTRAINT `battles_current_turn_user_id_foreign` FOREIGN KEY (`current_turn_user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `battles_player1_deck_id_foreign` FOREIGN KEY (`player1_deck_id`) REFERENCES `decks` (`id`) ON DELETE CASCADE,
  CONSTRAINT `battles_player1_id_foreign` FOREIGN KEY (`player1_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `battles_player2_deck_id_foreign` FOREIGN KEY (`player2_deck_id`) REFERENCES `decks` (`id`) ON DELETE CASCADE,
  CONSTRAINT `battles_player2_id_foreign` FOREIGN KEY (`player2_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `battles_winner_id_foreign` FOREIGN KEY (`winner_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
