DROP TABLE IF EXISTS `combos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `combos` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `card1_id` bigint unsigned NOT NULL,
  `card2_id` bigint unsigned NOT NULL,
  `card3_id` bigint unsigned NOT NULL,
  `leader_card_id` bigint unsigned NOT NULL,
  `attack_id` bigint unsigned NOT NULL,
  `endurance_cost` int NOT NULL DEFAULT '0',
  `cosmos_cost` int NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `combos_card1_id_foreign` (`card1_id`),
  KEY `combos_card2_id_foreign` (`card2_id`),
  KEY `combos_card3_id_foreign` (`card3_id`),
  KEY `combos_leader_card_id_foreign` (`leader_card_id`),
  KEY `combos_attack_id_foreign` (`attack_id`),
  CONSTRAINT `combos_attack_id_foreign` FOREIGN KEY (`attack_id`) REFERENCES `attacks` (`id`) ON DELETE CASCADE,
  CONSTRAINT `combos_card1_id_foreign` FOREIGN KEY (`card1_id`) REFERENCES `cards` (`id`) ON DELETE CASCADE,
  CONSTRAINT `combos_card2_id_foreign` FOREIGN KEY (`card2_id`) REFERENCES `cards` (`id`) ON DELETE CASCADE,
  CONSTRAINT `combos_card3_id_foreign` FOREIGN KEY (`card3_id`) REFERENCES `cards` (`id`) ON DELETE CASCADE,
  CONSTRAINT `combos_leader_card_id_foreign` FOREIGN KEY (`leader_card_id`) REFERENCES `cards` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

