INSERT INTO `factions` VALUES (1,'Chevaliers de Bronze','Les Chevaliers de Bronze sont les protecteurs d\'Athéna. Bien que considérés comme les plus faibles, leur détermination et leur courage les rendent redoutables.','#CD7F32','#8B4513',NULL,'2026-01-04 18:31:04','2026-01-04 18:31:04'),(2,'Chevaliers d\'Argent','Les Chevaliers d\'Argent sont plus puissants que les Chevaliers de Bronze. Ils servent souvent de messagers et d\'exécuteurs pour le Sanctuaire.','#C0C0C0','#808080',NULL,'2026-01-04 18:31:04','2026-01-04 18:31:04'),(3,'Chevaliers d\'Or','Les Chevaliers d\'Or sont l\'élite du Sanctuaire. Chacun protège une maison du zodiaque et possède une puissance cosmique extraordinaire.','#FFD700','#DAA520',NULL,'2026-01-04 18:31:04','2026-01-04 18:31:04'),(4,'Spectres d\'Hadès','Les Spectres sont les guerriers du dieu des Enfers, Hadès. Ils portent des Surplis noirs et cherchent à plonger le monde dans les ténèbres.','#4B0082','#1a0033',NULL,'2026-01-04 18:31:04','2026-01-04 18:31:04'),(5,'Marinas de Poséidon','Les Marinas sont les guerriers du dieu des mers, Poséidon. Ils portent des Écailles et contrôlent les forces océaniques.','#006994','#004466',NULL,'2026-01-04 18:31:04','2026-01-04 18:31:04'),(6,'Guerriers Divins d\'Asgard','Les Guerriers Divins protègent le royaume d\'Asgard sous les ordres d\'Hilda. Ils portent des armures représentant les étoiles d\'Odin.','#87CEEB','#4682B4',NULL,'2026-01-04 18:31:04','2026-01-04 18:31:04');
/*!40000 ALTER TABLE `factions` ENABLE KEYS */;
