DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `users` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `role` enum('admin','user') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'user',
  `has_selected_starter` tinyint(1) NOT NULL DEFAULT '0',
  `has_completed_first_draw` tinyint(1) NOT NULL DEFAULT '0',
  `starter_bronze_id` bigint unsigned DEFAULT NULL,
  `coins` int unsigned NOT NULL DEFAULT '500',
  `wins` int unsigned NOT NULL DEFAULT '0',
  `pve_wins` int unsigned NOT NULL DEFAULT '0',
  `pvp_wins` int unsigned NOT NULL DEFAULT '0',
  `losses` int unsigned NOT NULL DEFAULT '0',
  `tournament_wins` int NOT NULL DEFAULT '0',
  `tournament_title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tournament_points` int NOT NULL DEFAULT '0',
  `current_rank` enum('bronze','argent','or','divin') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'bronze',
  `last_daily_bonus_at` timestamp NULL DEFAULT NULL,
  `login_streak` tinyint unsigned NOT NULL DEFAULT '0',
  `last_login_date` date DEFAULT NULL,
  `streak_reward_claimed_today` tinyint(1) NOT NULL DEFAULT '0',
  `last_wheel_spin_at` timestamp NULL DEFAULT NULL,
  `last_weekly_card_at` timestamp NULL DEFAULT NULL,
  `last_activity_at` timestamp NULL DEFAULT NULL,
  `email_verified_at` timestamp NULL DEFAULT NULL,
  `password` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `remember_token` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `current_session_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `last_session_ip` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `users_email_unique` (`email`),
  KEY `users_starter_bronze_id_foreign` (`starter_bronze_id`),
  CONSTRAINT `users_starter_bronze_id_foreign` FOREIGN KEY (`starter_bronze_id`) REFERENCES `cards` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

